329	/** @internal */
330	export function getModuleInstanceState(node: ModuleDeclaration, visited?: Map<number, ModuleInstanceState | undefined>): ModuleInstanceState {
331	    if (node.body && !node.body.parent) {
332	        // getModuleInstanceStateForAliasTarget needs to walk up the parent chain, so parent pointers must be set on this tree already
333	        setParent(node.body, node);
334	        setParentRecursive(node.body, /*incremental*/ false);
335	    }
336	    return node.body ? getModuleInstanceStateCached(node.body, visited) : ModuleInstanceState.Instantiated;
337	}
