339	function getModuleInstanceStateCached(node: Node, visited = new Map<number, ModuleInstanceState | undefined>()) {
340	    const nodeId = getNodeId(node);
341	    if (visited.has(nodeId)) {
342	        return visited.get(nodeId) || ModuleInstanceState.NonInstantiated;
343	    }
344	    visited.set(nodeId, undefined);
345	    const result = getModuleInstanceStateWorker(node, visited);
346	    visited.set(nodeId, result);
347	    return result;
348	}
