351	    // A module is uninstantiated if it contains only
352	    switch (node.kind) {
353	        // 1. interface declarations, type alias declarations
354	        case SyntaxKind.InterfaceDeclaration:
355	        case SyntaxKind.TypeAliasDeclaration:
356	            return ModuleInstanceState.NonInstantiated;
357	        // 2. const enum declarations
358	        case SyntaxKind.EnumDeclaration:
359	            if (isEnumConst(node as EnumDeclaration)) {
360	                return ModuleInstanceState.ConstEnumOnly;
361	            }
362	            break;
363	        // 3. non-exported import declarations
364	        case SyntaxKind.ImportDeclaration:
365	        case SyntaxKind.ImportEqualsDeclaration:
366	            if (!(hasSyntacticModifier(node, ModifierFlags.Export))) {
367	                return ModuleInstanceState.NonInstantiated;
368	            }
369	            break;
370	        // 4. Export alias declarations pointing at only uninstantiated modules or things uninstantiated modules contain
371	        case SyntaxKind.ExportDeclaration:
372	            const exportDeclaration = node as ExportDeclaration;
373	            if (!exportDeclaration.moduleSpecifier && exportDeclaration.exportClause && exportDeclaration.exportClause.kind === SyntaxKind.NamedExports) {
374	                let state = ModuleInstanceState.NonInstantiated;
375	                for (const specifier of exportDeclaration.exportClause.elements) {
376	                    const specifierState = getModuleInstanceStateForAliasTarget(specifier, visited);
377	                    if (specifierState > state) {
378	                        state = specifierState;
379	                    }
380	                    if (state === ModuleInstanceState.Instantiated) {
381	                        return state;
382	                    }
383	                }
384	                return state;
385	            }
386	            break;
387	        // 5. other uninstantiated module declarations.
388	        case SyntaxKind.ModuleBlock: {
389	            let state = ModuleInstanceState.NonInstantiated;
390	            forEachChild(node, n => {
391	                const childState = getModuleInstanceStateCached(n, visited);
392	                switch (childState) {
393	                    case ModuleInstanceState.NonInstantiated:
394	                        // child is non-instantiated - continue searching
395	                        return;
396	                    case ModuleInstanceState.ConstEnumOnly:
397	                        // child is const enum only - record state and continue searching
398	                        state = ModuleInstanceState.ConstEnumOnly;
399	                        return;
400	                    case ModuleInstanceState.Instantiated:
401	                        // child is instantiated - record state and stop
402	                        state = ModuleInstanceState.Instantiated;
403	                        return true;
404	                    default:
405	                        Debug.assertNever(childState);
406	                }
407	            });
408	            return state;
409	        }
410	        case SyntaxKind.ModuleDeclaration:
411	            return getModuleInstanceState(node as ModuleDeclaration, visited);
412	        case SyntaxKind.Identifier:
413	            // Only jsdoc typedef definition can exist in jsdoc namespace, and it should
414	            // be considered the same as type alias
415	            if (node.flags & NodeFlags.IdentifierIsInJSDocNamespace) {
416	                return ModuleInstanceState.NonInstantiated;
417	            }
