422	function getModuleInstanceStateForAliasTarget(specifier: ExportSpecifier, visited: Map<number, ModuleInstanceState | undefined>) {
423	    const name = specifier.propertyName || specifier.name;
424	    if (name.kind !== SyntaxKind.Identifier) {
425	        return ModuleInstanceState.Instantiated; // Skip for invalid syntax like this: export { "x" }
426	    }
427	    let p: Node | undefined = specifier.parent;
428	    while (p) {
429	        if (isBlock(p) || isModuleBlock(p) || isSourceFile(p)) {
430	            const statements = p.statements;
431	            let found: ModuleInstanceState | undefined;
432	            for (const statement of statements) {
433	                if (nodeHasName(statement, name)) {
434	                    if (!statement.parent) {
435	                        setParent(statement, p);
436	                        setParentRecursive(statement, /*incremental*/ false);
437	                    }
438	                    const state = getModuleInstanceStateCached(statement, visited);
439	                    if (found === undefined || state > found) {
440	                        found = state;
441	                    }
442	                    if (found === ModuleInstanceState.Instantiated) {
443	                        return found;
444	                    }
445	                    if (statement.kind === SyntaxKind.ImportEqualsDeclaration) {
446	                        // Treat re-exports of import aliases as instantiated,
447	                        // since they're ambiguous. This is consistent with
448	                        // `export import x = mod.x` being treated as instantiated:
449	                        //   import x = mod.x;
450	                        //   export { x };
451	                        found = ModuleInstanceState.Instantiated;
452	                    }
453	                }
454	            }
455	            if (found !== undefined) {
456	                return found;
457	            }
458	        }
459	        p = p.parent;
460	    }
461	    return ModuleInstanceState.Instantiated; // Couldn't locate, assume could refer to a value
462	}
